const App = require("./app");
let pass = 0, fail = 0;
function eq(a, b, msg) {
  const ok = JSON.stringify(a) === JSON.stringify(b);
  console.log((ok ? "PASS" : "FAIL") + " " + msg + (ok ? "" : "  got=" + JSON.stringify(a) + " want=" + JSON.stringify(b)));
  ok ? pass++ : fail++;
}

// 1. Single route param
let app = new App();
app.get("/users/:id", (req) => ({ status: 200, body: req.params }));
eq(app.handle({ method: "GET", path: "/users/42" }), { status: 200, body: { id: "42" } }, "single param");

// 1b. Multiple params
app = new App();
app.get("/a/:x/b/:y", (req) => ({ status: 200, body: req.params }));
eq(app.handle({ method: "GET", path: "/a/1/b/2" }), { status: 200, body: { x: "1", y: "2" } }, "multi param");

// 2. Middleware runs in order before handler, next() continues
app = new App();
const order = [];
app.use((req, next) => { order.push("m1"); return next(); });
app.use((req, next) => { order.push("m2"); return next(); });
app.get("/x", (req) => { order.push("h"); return { status: 200, body: "ok" }; });
eq(app.handle({ method: "GET", path: "/x" }), { status: 200, body: "ok" }, "mw chain -> handler value");
eq(order, ["m1", "m2", "h"], "mw registration order before handler");

// 2b. Short-circuit: middleware returns response without next()
app = new App();
let handlerRan = false;
app.use((req, next) => ({ status: 401, body: "denied" }));
app.get("/y", (req) => { handlerRan = true; return { status: 200, body: "ok" }; });
eq(app.handle({ method: "GET", path: "/y" }), { status: 401, body: "denied" }, "short-circuit response");
eq(handlerRan, false, "handler skipped on short-circuit");

// 3. Method-aware 404 (path matches, method does not)
app = new App();
app.get("/z", () => ({ status: 200, body: "z" }));
eq(app.handle({ method: "POST", path: "/z" }), { status: 404, body: "Not Found" }, "404 wrong method");
eq(app.handle({ method: "GET", path: "/nope" }), { status: 404, body: "Not Found" }, "404 wrong path");

// 4. handler return value is the response
app = new App();
app.post("/p", (req) => ({ status: 201, body: "created" }));
eq(app.handle({ method: "POST", path: "/p" }), { status: 201, body: "created" }, "handler return is response");

// extra: middleware can read params
app = new App();
let seen = null;
app.use((req, next) => { seen = req.params; return next(); });
app.get("/users/:id", (req) => ({ status: 200, body: "ok" }));
app.handle({ method: "GET", path: "/users/7" });
eq(seen, { id: "7" }, "middleware sees params");

console.log("\n" + pass + " passed, " + fail + " failed");
process.exit(fail ? 1 : 0);
'

